const BIRTHDAY_NAME = "David"; // 🎉 Change this!

// Confetti
const Confetti = () => {
  const colors = ["#FF6B6B", "#FFE66D", "#4ECDC4", "#45B7D1", "#96CEB4", "#FFEEAD", "#FF9999", "#C9B1FF"];
  const pieces = Array.from({ length: 60 }, (_, i) => ({
    id: i,
    left: Math.random() * 100,
    delay: Math.random() * 3,
    duration: 2 + Math.random() * 3,
    color: colors[Math.floor(Math.random() * colors.length)],
    size: 6 + Math.random() * 10,
    rotation: Math.random() * 360,
    type: Math.random() > 0.5 ? "circle" : "rect",
  }));
  return (
    <div style={{ position: "fixed", top: 0, left: 0, width: "100%", height: "100%", pointerEvents: "none", zIndex: 1000, overflow: "hidden" }}>
      {pieces.map((p) => (
        <div key={p.id} style={{
          position: "absolute", left: `${p.left}%`, top: "-20px",
          width: p.type === "circle" ? p.size : p.size * 0.6, height: p.size,
          backgroundColor: p.color, borderRadius: p.type === "circle" ? "50%" : "2px",
          transform: `rotate(${p.rotation}deg)`,
          animation: `confettiFall ${p.duration}s ${p.delay}s ease-in infinite`,
        }} />
      ))}
      <style>{`@keyframes confettiFall { 0% { transform: translateY(0) rotate(0deg); opacity: 1; } 100% { transform: translateY(100vh) rotate(720deg); opacity: 0; } }`}</style>
    </div>
  );
};

// Floating emoji background
const FloatingEmojis = ({ emojis = ["🎈", "🎁", "🎊", "⭐", "🎵"] }) => {
  const items = Array.from({ length: 12 }, (_, i) => ({
    id: i, emoji: emojis[i % emojis.length],
    left: Math.random() * 100, delay: Math.random() * 8,
    duration: 6 + Math.random() * 6, size: 20 + Math.random() * 20,
  }));
  return (
    <div style={{ position: "fixed", top: 0, left: 0, width: "100%", height: "100%", pointerEvents: "none", zIndex: 1, overflow: "hidden" }}>
      {items.map((item) => (
        <div key={item.id} style={{
          position: "absolute", left: `${item.left}%`, bottom: "-40px",
          fontSize: item.size, animation: `floatUp ${item.duration}s ${item.delay}s ease-in-out infinite`, opacity: 0.3,
        }}>{item.emoji}</div>
      ))}
      <style>{`@keyframes floatUp { 0% { transform: translateY(0) rotate(0deg); opacity: 0.3; } 50% { opacity: 0.5; } 100% { transform: translateY(-110vh) rotate(180deg); opacity: 0; } }`}</style>
    </div>
  );
};

// Clickable card button
const CardButton = ({ label, emoji, gradient, size = 120, onClick }) => (
  <div
    onClick={onClick}
    style={{
      width: size, height: size, background: gradient, borderRadius: 16,
      display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
      cursor: "pointer", transition: "all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1)",
      boxShadow: "0 4px 15px rgba(0,0,0,0.2)", border: "3px solid rgba(255,255,255,0.6)",
    }}
    onMouseEnter={(e) => { e.currentTarget.style.transform = "scale(1.08) rotate(2deg)"; e.currentTarget.style.boxShadow = "0 8px 25px rgba(0,0,0,0.3)"; }}
    onMouseLeave={(e) => { e.currentTarget.style.transform = "scale(1) rotate(0deg)"; e.currentTarget.style.boxShadow = "0 4px 15px rgba(0,0,0,0.2)"; }}
  >
    <span style={{ fontSize: size * 0.35 }}>{emoji}</span>
    {label && <span style={{ color: "white", fontSize: 11, fontWeight: 700, marginTop: 4, textShadow: "0 1px 3px rgba(0,0,0,0.4)", textAlign: "center", padding: "0 8px", lineHeight: 1.2 }}>{label}</span>}
  </div>
);

